import express from "express";
import path from "path";
import { createServer as createViteServer } from "vite";
import { GoogleGenAI } from "@google/genai";
import dotenv from "dotenv";

dotenv.config();

async function startServer() {
  const app = express();
  const PORT = 3000;

  app.use(express.json());

  // AI Chat Route
  app.post("/api/chat", async (req, res) => {
    try {
      const { message, code, error, language, instruction } = req.body;
      
      const ai = new GoogleGenAI({
        apiKey: process.env.GEMINI_API_KEY,
        httpOptions: {
          headers: {
            'User-Agent': 'aistudio-build',
          }
        }
      });

      const prompt = `あなたはプログラミング初学者向けの優しいAIチューターです。
ユーザーは現在${language === "typescript" ? "TypeScript" : "JavaScript"}の学習中です。

【現在のミッション】
${instruction}

【ユーザーの現在のコード】
\`\`\`${language}
${code}
\`\`\`

【コンソールエラー（あれば）】
${error || "なし"}

【ユーザーの質問・コメント】
${message}

上記の情報を元に、ユーザーの質問に答えたり、エラーの原因を優しく日本語で解説してください。
答えを直接教えるのではなく、ヒントを出してユーザー自身が気づけるようにサポートしてください。
専門用語はなるべく使わず、使う場合は簡単な解説を入れてください。`;

      const response = await ai.models.generateContent({
        model: "gemini-3.1-flash-lite",
        contents: prompt,
      });

      res.json({ text: response.text });
    } catch (err: any) {
      console.error("AI Chat Error:", err);
      res.status(500).json({ error: "AIアシスタントに接続できませんでした。" });
    }
  });

  // Error Explain Route
  app.post("/api/explain-error", async (req, res) => {
    try {
      const { code, error, language, instruction } = req.body;
      
      const ai = new GoogleGenAI({
        apiKey: process.env.GEMINI_API_KEY,
        httpOptions: { headers: { 'User-Agent': 'aistudio-build' } }
      });

      const prompt = `あなたはプログラミング初学者向けのAIチューターです。
ユーザーが以下の課題に取り組んでいる最中にエラーが発生しました。
エラーの原因と解決のヒントを、初学者向けに「数行程度で超簡潔に」解説してください。答えのコードは直接書かないでください。

【課題】
${instruction}

【言語】
${language}

【ユーザーのコード】
\`\`\`${language}
${code}
\`\`\`

【発生したエラー】
${error}
`;

      const response = await ai.models.generateContent({
        model: "gemini-3.1-flash-lite",
        contents: prompt,
      });

      res.json({ explanation: response.text });
    } catch (err: any) {
      console.error("Explain Error:", err);
      res.status(500).json({ error: "エラーの分析に失敗しました。" });
    }
  });

  // Generate Challenge Route
  app.post("/api/generate-challenge", async (req, res) => {
    try {
      const { lesson, level } = req.body;
      
      const ai = new GoogleGenAI({
        apiKey: process.env.GEMINI_API_KEY,
        httpOptions: { headers: { 'User-Agent': 'aistudio-build' } }
      });

      let promptModifier = "この課題に似た、少しだけ内容を変更した新しいチャレンジ課題を作成してください。";
      if (level === 'harder') {
        promptModifier = "この課題の知識を応用し、少し難易度を上げた新しい応用課題を作成してください。";
      }

      const prompt = `あなたはプログラミング初学者向けのAIチューターです。
ユーザーが以下の課題をクリアしました。${promptModifier}
フォーマットは必ず以下のJSON形式で返してください。マークダウンブロックやその他のテキストは一切含めないでください。

【元の課題】
タイトル: ${lesson.title}
内容: ${lesson.instruction}
言語: ${lesson.language}

【出力JSONの形式】
{
  "id": "challenge_${Date.now()}",
  "title": "${level === 'harder' ? '応用問題: ' : '類題: '}...",
  "description": "...",
  "instruction": "...",
  "example": "...",
  "initialCode": "...",
  "language": "${lesson.language}",
  "hint": "...",
  "answer": "...",
  "explanation": "...",
  "successMessage": "...",
  "testCode": "return logs.some(log => log.includes('...'))" // logsとcodeを受け取る関数のボディ文字列
}
`;

      const response = await ai.models.generateContent({
        model: "gemini-3.1-flash-lite",
        contents: prompt,
      });

      let jsonStr = response.text || "{}";
      jsonStr = jsonStr.replace(/```json/gi, "").replace(/```/g, "").trim();

      const challengeData = JSON.parse(jsonStr);
      res.json(challengeData);
    } catch (err: any) {
      console.error("Generate Challenge Error:", err);
      res.status(500).json({ error: "チャレンジ課題の生成に失敗しました。" });
    }
  });

  // Autocomplete Route
  app.post("/api/autocomplete", async (req, res) => {
    try {
      const { codeBefore, codeAfter, language, instruction } = req.body;
      
      const ai = new GoogleGenAI({
        apiKey: process.env.GEMINI_API_KEY,
        httpOptions: { headers: { 'User-Agent': 'aistudio-build' } }
      });

      const prompt = `あなたはプログラミング初学者の学習をサポートするAIです。
ユーザーがコードを記述中ですが、学習の妨げにならないよう、次に入力すべき「単語1つ」または「数文字」程度の入力補助のみを提案してください。
【重要】
- 絶対に課題の解答全体や、長い行を書かないでください。
- ユーザーが自力で考える余地を残すため、現在のカーソル位置から続く「1単語」または「短い記号や式（最大10文字程度）」のみを提案してください。
- マークダウンのコードブロック（\`\`\`javascriptなど）や説明文は一切不要です。提案するコードの文字列のみを出力してください。

【現在の課題】
${instruction}

【言語】
${language}

【カーソル位置より前のコード】
${codeBefore}

【カーソル位置より後のコード】
${codeAfter}
`;

      const response = await ai.models.generateContent({
        model: "gemini-3.1-flash-lite",
        contents: prompt,
      });

      let completion = response.text || "";
      // Strip markdown code blocks if any
      completion = completion.replace(/^```[a-z]*\n/i, "").replace(/\n```$/i, "");

      res.json({ completion: completion.trimEnd() });
    } catch (err: any) {
      console.error("Autocomplete Error:", err);
      res.json({ completion: "" }); // Fail silently for autocomplete
    }
  });

  // Vite middleware for development
  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), 'dist');
    app.use(express.static(distPath));
    app.get('*', (req, res) => {
      res.sendFile(path.join(distPath, 'index.html'));
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`Server running on http://localhost:${PORT}`);
  });
}

startServer();
